import { VietQRBasic } from './BasicQR';
import { VietQRCompactCard } from './CompactCard';
import { VietQRPayStandee } from './PayStandee';
import { VietQRButtonElement } from './VietQRButton';

export { VietQRBasic, VietQRCompactCard, VietQRPayStandee, VietQRButtonElement };

/**
 * Đăng ký các Web Components (Custom Elements) vào trình duyệt.
 * Sau khi gọi hàm này, bạn có thể sử dụng các thẻ HTML như:
 * <viet-qr-basic></viet-qr-basic>
 * <viet-qr-compact></viet-qr-compact>
 * <viet-qr-standee></viet-qr-standee>
 */
export function registerElements() {
  if (typeof window !== 'undefined' && window.customElements) {
    if (!customElements.get('viet-qr-basic')) {
      customElements.define('viet-qr-basic', VietQRBasic);
    }
    if (!customElements.get('viet-qr-compact')) {
      customElements.define('viet-qr-compact', VietQRCompactCard);
    }
    if (!customElements.get('viet-qr-standee')) {
      customElements.define('viet-qr-standee', VietQRPayStandee);
    }
    if (!customElements.get('viet-qr-button')) {
      customElements.define('viet-qr-button', VietQRButtonElement);
    }
  }
}
