import { generateVietQR } from '@viet-qr/core';
import QRCode from 'qrcode';

export class VietQRButtonElement extends HTMLElement {
  static get observedAttributes() {
    return [
      'bank-id',
      'account-no',
      'account-name',
      'amount',
      'content',
      'size',
      'label',
      'variant'
    ];
  }

  private button: HTMLButtonElement | null = null;
  private overlay: HTMLDivElement | null = null;
  private qrContainer: HTMLDivElement | null = null;
  private amountP: HTMLParagraphElement | null = null;
  private accountNameP: HTMLParagraphElement | null = null;
  private accountNoP: HTMLParagraphElement | null = null;
  
  private isOpen = false;

  constructor() {
    super();
    this.attachShadow({ mode: 'open' });
  }

  connectedCallback() {
    this.renderInitial();
    this.updateData();
    this.bindEvents();
  }

  disconnectedCallback() {
    this.unbindEvents();
  }

  attributeChangedCallback() {
    if (this.button) {
      this.updateData();
    }
  }

  private renderInitial() {
    const variant = this.getAttribute('variant') || 'default';
    const label = this.getAttribute('label') || 'Thanh toán VietQR';

    this.shadowRoot!.innerHTML = `
      <style>
        .vqr-btn {
          display: inline-flex;
          align-items: center;
          gap: 8px;
          padding: 10px 20px;
          border-radius: 10px;
          font-size: 15px;
          font-weight: 600;
          cursor: pointer;
          border: none;
          font-family: inherit;
          transition: all 0.2s ease;
        }
        .vqr-btn:hover { filter: brightness(1.08); transform: translateY(-1px); }
        .vqr-btn:active { transform: translateY(0); }
        .vqr-btn--default { background: linear-gradient(135deg, #0051cc 0%, #0070f3 100%); color: #ffffff; box-shadow: 0 2px 8px rgba(0, 112, 243, 0.35); }
        .vqr-btn--outline { background: transparent; color: #0070f3; border: 2px solid #0070f3; }
        .vqr-btn--ghost { background: rgba(0, 112, 243, 0.08); color: #0070f3; }
        
        .vqr-overlay {
          position: fixed; inset: 0; background: rgba(0, 0, 0, 0.6); backdrop-filter: blur(4px);
          display: flex; align-items: center; justify-content: center; z-index: 9999; padding: 16px;
          opacity: 0; transition: opacity 0.2s ease;
        }
        .vqr-modal {
          background: #ffffff; border-radius: 20px; padding: 28px 24px 24px;
          width: 100%; max-width: 340px; position: relative; box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
          transform: translateY(20px); transition: transform 0.25s ease, opacity 0.2s ease; opacity: 0;
        }
        .vqr-modal.show { transform: translateY(0); opacity: 1; }
        .vqr-modal__close {
          position: absolute; top: 14px; right: 16px; background: rgba(0,0,0,0.07);
          border: none; border-radius: 50%; width: 32px; height: 32px; display: flex;
          align-items: center; justify-content: center; cursor: pointer; font-size: 16px; color: #666; transition: background 0.2s;
        }
        .vqr-modal__close:hover { background: rgba(0,0,0,0.14); }
        .vqr-modal__title { text-align: center; margin: 0 0 16px 0; font-weight: 700; font-size: 17px; color: #000; }
        .vqr-modal__qr {
          display: flex; justify-content: center; align-items: center; padding: 12px;
          background: #f8f9fa; border-radius: 12px; margin-bottom: 16px;
        }
        .vqr-modal__amount { text-align: center; font-weight: 700; font-size: 16px; color: #0070f3; margin: 0 0 6px 0; }
        .vqr-modal__hint { text-align: center; font-size: 13px; color: #888; margin: 0 0 4px 0; }
      </style>

      <button class="vqr-btn vqr-btn--${variant}" type="button">
        <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round">
          <rect x="3" y="3" width="7" height="7"/><rect x="14" y="3" width="7" height="7"/><rect x="3" y="14" width="7" height="7"/>
          <line x1="14" y1="14" x2="14" y2="14"/><line x1="17" y1="14" x2="17" y2="14"/><line x1="20" y1="14" x2="20" y2="14"/>
          <line x1="14" y1="17" x2="14" y2="17"/><line x1="17" y1="17" x2="20" y2="17"/>
          <line x1="20" y1="20" x2="20" y2="20"/>
        </svg>
        <span class="vqr-btn-label">${label}</span>
      </button>

      <div class="vqr-overlay" style="display: none;" role="dialog" aria-modal="true">
        <div class="vqr-modal">
          <button class="vqr-modal__close" aria-label="Đóng">✕</button>
          <p class="vqr-modal__title">Quét mã để thanh toán</p>
          <div class="vqr-modal__qr"></div>
          <p class="vqr-modal__amount"></p>
          <p class="vqr-modal__hint account-name"></p>
          <p class="vqr-modal__hint account-no"></p>
        </div>
      </div>
    `;

    this.button = this.shadowRoot!.querySelector('.vqr-btn');
    this.overlay = this.shadowRoot!.querySelector('.vqr-overlay');
    this.qrContainer = this.shadowRoot!.querySelector('.vqr-modal__qr');
    this.amountP = this.shadowRoot!.querySelector('.vqr-modal__amount');
    this.accountNameP = this.shadowRoot!.querySelector('.account-name');
    this.accountNoP = this.shadowRoot!.querySelector('.account-no');
  }

  private bindEvents() {
    this.button?.addEventListener('click', this.openModal);
    
    const closeBtn = this.shadowRoot!.querySelector('.vqr-modal__close');
    closeBtn?.addEventListener('click', this.closeModal);
    
    this.overlay?.addEventListener('click', (e) => {
      if (e.target === this.overlay) {
        this.closeModal();
      }
    });

    document.addEventListener('keydown', this.handleKeydown);
  }

  private unbindEvents() {
    this.button?.removeEventListener('click', this.openModal);
    document.removeEventListener('keydown', this.handleKeydown);
  }

  private openModal = () => {
    this.isOpen = true;
    if (this.overlay) {
      this.overlay.style.display = 'flex';
      // force reflow
      void this.overlay.offsetWidth;
      this.overlay.style.opacity = '1';
    }
    const modal = this.shadowRoot!.querySelector('.vqr-modal') as HTMLElement;
    if (modal) {
      modal.classList.add('show');
    }
    document.body.style.overflow = 'hidden';
  }

  private closeModal = () => {
    this.isOpen = false;
    if (this.overlay) {
      this.overlay.style.opacity = '0';
      const modal = this.shadowRoot!.querySelector('.vqr-modal') as HTMLElement;
      if (modal) modal.classList.remove('show');
      setTimeout(() => {
        if (!this.isOpen && this.overlay) this.overlay.style.display = 'none';
      }, 200);
    }
    document.body.style.overflow = '';
  }

  private handleKeydown = (e: KeyboardEvent) => {
    if (e.key === 'Escape' && this.isOpen) {
      this.closeModal();
    }
  }

  private updateData() {
    const bankId = this.getAttribute('bank-id');
    const accountNo = this.getAttribute('account-no');
    if (!bankId || !accountNo) return;

    const accountName = this.getAttribute('account-name');
    const amountStr = this.getAttribute('amount');
    const amount = amountStr ? parseInt(amountStr, 10) : undefined;
    const content = this.getAttribute('content') || undefined;
    
    const label = this.getAttribute('label') || 'Thanh toán VietQR';
    const variant = this.getAttribute('variant') || 'default';
    
    // Update button visual
    if (this.button) {
      this.button.className = 'vqr-btn vqr-btn--' + variant;
      const labelSpan = this.button.querySelector('.vqr-btn-label');
      if (labelSpan) labelSpan.textContent = label;
    }

    // Format amount
    if (this.amountP) {
      if (amount) {
        this.amountP.textContent = new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(amount);
        this.amountP.style.display = 'block';
      } else {
        this.amountP.style.display = 'none';
      }
    }

    // Account infos
    if (this.accountNameP) {
      if (accountName) {
        this.accountNameP.textContent = accountName;
        this.accountNameP.style.display = 'block';
      } else {
        this.accountNameP.style.display = 'none';
      }
    }
    
    if (this.accountNoP) {
      this.accountNoP.textContent = accountNo;
    }

    // Generate QR
    try {
      const payload = generateVietQR({
        bankId,
        accountNo,
        accountName: accountName || undefined,
        amount,
        content
      });

      const sizeStr = this.getAttribute('size');
      const size = sizeStr ? parseInt(sizeStr, 10) : 260;

      QRCode.toString(payload, {
        type: 'svg',
        width: size,
        margin: 0,
        errorCorrectionLevel: 'Q'
      }, (err, svgString) => {
        if (!err && this.qrContainer) {
          this.qrContainer.innerHTML = svgString;
        }
      });
    } catch (e) {
      console.error('VietQR Generation Error:', e);
      if (this.qrContainer) {
        this.qrContainer.innerHTML = '';
      }
    }
  }
}
